/**
 * Seed the Sanity blog: a single brand author (Hommy), four categories, and 24
 * researched roofing articles with auto-generated cover images.
 *
 *   pnpm blog:seed            # full wipe + rebuild (idempotent)
 *
 * Covers are generated by the dynamic OG route (src/app/og/blog/route.tsx):
 * the script fetches /og/blog?t=<title>&c=<category>, then uploads the PNG to
 * Sanity as the post's mainImage. That route must be reachable while seeding,
 * so run `pnpm dev` in another terminal (default base http://localhost:3000) or
 * point OG_BASE_URL at a deployed instance.
 *
 * Requires SANITY_API_DEV_TOKEN (read+write) in .env.
 */

const token = process.env.SANITY_API_DEV_TOKEN
if (!token) {
  console.error('Missing SANITY_API_DEV_TOKEN in .env. Needs a read+write token.')
  process.exit(1)
}

const OG_BASE = (process.env.OG_BASE_URL ?? 'http://localhost:3000').replace(/\/$/, '')

const client = createClient({
  projectId,
  dataset,
  apiVersion,
  token,
  useCdn: false,
  // 'raw' so the wipe sees BOTH published and draft (drafts.*) documents;
  // otherwise a leftover draft can reference a published post and block its
  // deletion with a 409.
  perspective: 'raw',
})

const PUBLIC_DIR = resolve(process.cwd(), 'public')

// ---------------------------------------------------------------------------
// Portable Text helpers
// ---------------------------------------------------------------------------

const key = () => randomUUID().slice(0, 12)

type Span = {_type: 'span'; _key: string; text: string; marks: string[]}

function span(text: string, marks: string[] = []): Span {
  return {_type: 'span', _key: key(), text, marks}
}

function block(style: string, children: Span[], extra: Record<string, unknown> = {}) {
  return {_type: 'block', _key: key(), style, markDefs: [], children, ...extra}
}

const p = (text: string) => block('normal', [span(text)])
const h2 = (text: string) => block('h2', [span(text)])

function bullets(items: string[]) {
  return items.map((item) => block('normal', [span(item)], {listItem: 'bullet', level: 1}))
}

function numbered(items: string[]) {
  return items.map((item) => block('normal', [span(item)], {listItem: 'number', level: 1}))
}

function callout(tone: 'info' | 'tip' | 'warning' | 'success', title: string, content: string) {
  return {_type: 'callout', _key: key(), tone, title, content}
}

function pullQuote(quote: string, attribution = 'The Hommy Team') {
  return {_type: 'pullQuote', _key: key(), quote, attribution}
}

function cta(label: string, href = 'https://hommy.online/get-a-quote', variant: 'primary' | 'secondary' = 'primary') {
  return {
    _type: 'cta',
    _key: key(),
    label,
    variant,
    link: {_type: 'link', linkType: 'external', href, openInNewTab: false},
  }
}

// A normal paragraph that can carry inline links. Each segment is either a plain
// string, an internal link to another post ({text, post}), or an external link
// ({text, href}). Internal links use the schema's link annotation with an
// internalLink reference so the renderer resolves them to /blog/<slug>.
type Seg = string | {text: string; post: string} | {text: string; href: string}

function lp(segments: Seg[]) {
  const markDefs: Record<string, unknown>[] = []
  const children = segments.map((seg) => {
    if (typeof seg === 'string') return span(seg)
    const k = key()
    if ('post' in seg) {
      markDefs.push({
        _type: 'link',
        _key: k,
        linkType: 'internal',
        // weak so creation order does not matter (post A may link post Z before
        // Z exists); the reference still resolves in GROQ/the renderer.
        internalLink: {_type: 'reference', _ref: `post-${seg.post}`, _weak: true},
        openInNewTab: false,
      })
    } else {
      markDefs.push({_type: 'link', _key: k, linkType: 'external', href: seg.href, openInNewTab: true})
    }
    return span(seg.text, [k])
  })
  return {_type: 'block', _key: key(), style: 'normal', markDefs, children}
}

// ---------------------------------------------------------------------------
// Cover image generation (via the /og/blog route) + brand avatar upload
// ---------------------------------------------------------------------------

const assetCache = new Map<string, string>()

async function uploadFromBuffer(filename: string, buf: Buffer, contentType: string): Promise<string> {
  if (assetCache.has(filename)) return assetCache.get(filename)!
  const existing = await client.fetch<string | null>(
    '*[_type == "sanity.imageAsset" && originalFilename == $filename][0]._id',
    {filename},
  )
  if (existing) {
    assetCache.set(filename, existing)
    return existing
  }
  const asset = await client.assets.upload('image', buf, {filename, contentType})
  assetCache.set(filename, asset._id)
  return asset._id
}

async function uploadCover(slug: string, title: string, categoryTitle: string): Promise<string> {
  const url = `${OG_BASE}/og/blog?t=${encodeURIComponent(title)}&c=${encodeURIComponent(categoryTitle)}`
  const res = await fetch(url)
  if (!res.ok) {
    throw new Error(
      `Cover generation failed for "${slug}" (${res.status} ${res.statusText}). ` +
        `Is the app running at ${OG_BASE}? Set OG_BASE_URL or run \`pnpm dev\`.`,
    )
  }
  const buf = Buffer.from(await res.arrayBuffer())
  return uploadFromBuffer(`${slug}.png`, buf, 'image/png')
}

async function uploadLogo(relPath: string): Promise<string> {
  const filename = relPath.split('/').pop()!
  if (assetCache.has(filename)) return assetCache.get(filename)!
  const existing = await client.fetch<string | null>(
    '*[_type == "sanity.imageAsset" && originalFilename == $filename][0]._id',
    {filename},
  )
  if (existing) {
    assetCache.set(filename, existing)
    return existing
  }
  const abs = resolve(PUBLIC_DIR, relPath)
  const asset = await client.assets.upload('image', createReadStream(abs), {filename})
  assetCache.set(filename, asset._id)
  return asset._id
}

