// ---------------------------------------------------------------------------
// Seed
// ---------------------------------------------------------------------------

function isoDaysAgo(days: number): string {
  const ms = Date.now() - days * 24 * 60 * 60 * 1000
  return new Date(ms).toISOString()
}

async function wipe() {
  // Delete posts first (they hold the references to authors/categories), then
  // the rest. relatedPosts references among posts are removed together.
  for (const type of ['post', 'category', 'author'] as const) {
    const ids = await client.fetch<string[]>('*[_type == $type]._id', {type})
    if (ids.length) {
      let tx = client.transaction()
      for (const id of ids) tx = tx.delete(id)
      await tx.commit()
    }
    console.log(`  wiped   ✓ ${ids.length} ${type}${ids.length === 1 ? '' : 's'}`)
  }
}

async function main() {
  console.log(`Seeding blog into ${projectId}/${dataset} (covers via ${OG_BASE})\n`)

  // 0. Wipe everything
  await wipe()

  // 1. Author (single brand byline)
  const logoId = await uploadLogo('logo/logo.png')
  await client.createOrReplace({
    _id: AUTHOR_ID,
    _type: 'author',
    name: 'Hommy',
    slug: {_type: 'slug', current: 'hommy'},
    role: 'Home Services Editorial Team',
    image: {_type: 'image', asset: {_type: 'reference', _ref: logoId}, alt: 'Hommy'},
  })
  console.log(`  author  ✓ Hommy`)

  // 2. Categories
  for (const cat of categories) {
    await client.createOrReplace({
      _id: cat._id,
      _type: 'category',
      title: cat.title,
      slug: {_type: 'slug', current: cat.slug},
      description: cat.description,
    })
    console.log(`  category ✓ ${cat.title}`)
  }

  // 3. Posts (generate cover, then create; relatedPosts patched in a 2nd pass)
  for (const post of posts) {
    const coverId = await uploadCover(post.slug, post.title, post.cover)
    await client.createOrReplace({
      _id: `post-${post.slug}`,
      _type: 'post',
      title: post.title,
      slug: {_type: 'slug', current: post.slug},
      eyebrow: post.eyebrow,
      excerpt: post.excerpt,
      mainImage: {_type: 'image', asset: {_type: 'reference', _ref: coverId}, alt: post.title},
      body: post.body,
      category: {_type: 'reference', _ref: post.category},
      author: {_type: 'reference', _ref: AUTHOR_ID},
      publishedAt: isoDaysAgo(post.daysAgo),
      readTime: post.readTime,
      featured: post.featured ?? false,
      seo: {
        metaTitle: post.title.slice(0, 60),
        metaDescription: post.excerpt.slice(0, 160),
        noIndex: false,
      },
    })
    console.log(`  post     ✓ ${post.title}`)
  }

  // 4. Related posts (second pass, all targets now exist)
  for (const post of posts) {
    if (!post.related?.length) continue
    await client
      .patch(`post-${post.slug}`)
      .set({
        relatedPosts: post.related.slice(0, 3).map((slug) => ({
          _type: 'reference',
          _key: key(),
          _ref: `post-${slug}`,
        })),
      })
      .commit()
  }

  console.log(`\nDone. 1 author, ${categories.length} categories, ${posts.length} posts.`)
}

main().catch((err) => {
  console.error(err)
  process.exit(1)
})
